const body = $input.first().json.body;
const data = body.data;

if (!data || !data.key) return [];
if (data.key.fromMe) return [];

const remoteJid = data.key.remoteJid;
const phoneNumber = remoteJid
  .replace('@s.whatsapp.net', '')
  .replace('@g.us', '')
  .replace('@lid', '');

const pushName = data.pushName || 'Campista';
const messageType = data.messageType || '';
const textMessage = data.message?.conversation ||
  data.message?.extendedTextMessage?.text || '';
const isAudio = messageType === 'audioMessage' || messageType === 'pttMessage';
const isImage = messageType === 'imageMessage';
const imageCaption = data.message?.imageMessage?.caption || '';

if (!textMessage && !isAudio && !isImage) return [];

// Get current date from message timestamp
const msgTimestamp = data.messageTimestamp;
const currentDate = msgTimestamp 
  ? new Date(msgTimestamp * 1000) 
  : new Date();

return [{
  json: {
    phoneNumber,
    remoteJid,
    fullBody: body,
    instanceName: 'CPVCV2',
    pushName,
    messageType,
    textMessage: isImage ? (imageCaption || '[Imagen enviada]') : textMessage,
    isAudio,
    isImage,
    rawMessage: data.message,
    messageId: data.key.id,
    timestamp: currentDate.toISOString(),
    currentDate: currentDate.toISOString().split('T')[0],
    currentDayName: currentDate.toLocaleDateString('es-CR', { weekday: 'long' }),
    currentDateFormatted: currentDate.toLocaleDateString('es-CR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })
  }
}];

const base64Audio = $input.first().json.base64;
const phoneNumber = $('Detectar tipo de mensaje').first().json.phoneNumber;
const pushName = $('Detectar tipo de mensaje').first().json.pushName;
const remoteJid = $('Detectar tipo de mensaje').first().json.remoteJid;

if (!base64Audio) {
  return [{
    json: {
      phoneNumber, remoteJid, pushName,
      textMessage: '[El cliente envió un audio pero no se pudo procesar]',
      isAudio: true, audioReady: false
    }
  }];
}

const audioBuffer = Buffer.from(base64Audio, 'base64');

return [{
  json: { phoneNumber, remoteJid, pushName, isAudio: true, audioReady: true },
  binary: {
    audio: { data: audioBuffer, mimeType: 'audio/ogg', fileName: 'audio.ogg' }
  }
}];

let textMessage = '';
let phoneNumber = '';
let remoteJid = '';
let pushName = '';
let isTranscribed = false;
let isImage = false;

const inputData = $input.first().json;

if (inputData.text) {
  textMessage = inputData.text;
  phoneNumber = $('Preparar audio para Whisper').first().json.phoneNumber;
  remoteJid = $('Preparar audio para Whisper').first().json.remoteJid;
  pushName = $('Preparar audio para Whisper').first().json.pushName;
  isTranscribed = true;
} else {
  textMessage = $('Detectar tipo de mensaje').first().json.textMessage;
  phoneNumber = $('Detectar tipo de mensaje').first().json.phoneNumber;
  remoteJid = $('Detectar tipo de mensaje').first().json.remoteJid;
  pushName = $('Detectar tipo de mensaje').first().json.pushName;
  isImage = $('Detectar tipo de mensaje').first().json.isImage || false;
}

if (!textMessage || !textMessage.trim()) {
  if (!isImage) return [];
  textMessage = '[Imagen enviada]';
}

return [{
  json: {
    phoneNumber, remoteJid, pushName,
    textMessage: textMessage.trim(),
    isTranscribed, isImage,
    messageId: $('Detectar tipo de mensaje').first().json.messageId,
    timestamp: new Date().toISOString()
  }
}];

// Obtener historial de conversación desde Redis
const phoneNumber = $input.first().json.phoneNumber;
const redisKey = `cori:conv:${phoneNumber}`;

// Retornar la key para que el nodo Redis la use
return [{
  json: {
    ...($input.first().json),
    redisKey
  }
}];

const msgData = $('Preparar clave Redis').first().json;
const phoneNumber = msgData.phoneNumber;
const remoteJid = msgData.remoteJid;
const pushName = msgData.pushName;
const textMessage = msgData.textMessage;
const redisKey = msgData.redisKey;
const isImage = msgData.isImage || false;
const messageId = msgData.messageId || '';

let historyRaw = $input.first().json.value || null;
let conversationHistory = [];
let clientName = null;
let reservationInfoSent = false;
let followUpSent = false;
let mediaSentCategories = {};
let bookingState = {
  phase: 'idle', data: { checkIn:null, checkOut:null, nights:0, adults:0, children:0, infants:0,
    guestName:null, guestEmail:null, guestPhone:phoneNumber, guestCountry:null, totalCRC:0 },
  referenceCode:null, receiptAttempts:0, receiptVerified:false, depositCRC:0, lastActionResult:null
};
let lookupState = { active:false, referenceCode:null, bookingData:null, intent:null };

if (historyRaw) {
  try {
    const parsed = JSON.parse(historyRaw);
    conversationHistory = parsed.messages || [];
    clientName = parsed.clientName || null;
    reservationInfoSent = parsed.reservationInfoSent || false;
    followUpSent = parsed.followUpSent || false;
    mediaSentCategories = parsed.mediaSentCategories || {};
    if (parsed.bookingState) bookingState = { ...bookingState, ...parsed.bookingState };
    if (parsed.lookupState) lookupState = { ...lookupState, ...parsed.lookupState };
  } catch(e) { conversationHistory = []; }
}

if (!clientName && conversationHistory.length > 0) {
  for (const msg of conversationHistory) {
    if (msg.role === 'assistant') {
      const match = msg.content.match(/Gracias\s+(\w+)\s+por/i);
      if (match) { clientName = match[1]; break; }
    }
  }
}

conversationHistory.push({ role: 'user', content: textMessage, timestamp: new Date().toISOString() });
if (conversationHistory.length > 20) conversationHistory = conversationHistory.slice(-20);

const claudeMessages = conversationHistory.filter(m => m.content && m.content.trim() !== '').map(m => ({ role: m.role, content: m.content }));
if (claudeMessages.length === 0) claudeMessages.push({ role: 'user', content: textMessage });

// Inject current date so Claude knows what day it is
const currentDate = msgData.currentDate || new Date().toISOString().split('T')[0];
const currentDateFormatted = msgData.currentDateFormatted || new Date().toLocaleDateString('es-CR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
claudeMessages.unshift({
  role: 'user',
  content: '[FECHA ACTUAL: Hoy es ' + currentDateFormatted + ' (' + currentDate + '). Usá esta fecha como referencia cuando el cliente diga "este fin de semana", "mañana", "el próximo viernes", etc.]'
});
claudeMessages.splice(1, 0, {
  role: 'assistant',
  content: 'Entendido, hoy es ' + currentDateFormatted + '.'
});

if (clientName) {
  claudeMessages.unshift({ role: 'user', content: '[CONTEXTO INTERNO: El nombre del cliente es ' + clientName + '. NO pid\u00e1s el nombre de nuevo.]' });
  claudeMessages.splice(1, 0, { role: 'assistant', content: 'Entendido, el cliente se llama ' + clientName + '.' });
}

if (bookingState.phase !== 'idle') {
  claudeMessages.push({ role: 'user', content: '[ESTADO RESERVA: Fase=' + bookingState.phase + ' Datos=' + JSON.stringify(bookingState.data) + ' Ref=' + (bookingState.referenceCode||'pendiente') + ' Intentos recibo=' + bookingState.receiptAttempts + '/3 Verificado=' + bookingState.receiptVerified + (bookingState.lastActionResult ? ' UltimoResultado=' + JSON.stringify(bookingState.lastActionResult) : '') + ']' });
}

if (isImage) {
  claudeMessages.push({ role: 'user', content: '[CONTEXTO: El cliente envi\u00f3 una IMAGEN. Si est\u00e1 en fase awaiting_payment, es el comprobante SINPE. El sistema lo verificar\u00e1 autom\u00e1ticamente.]' });
}

const sentCats = Object.keys(mediaSentCategories).filter(k => mediaSentCategories[k]);
if (sentCats.length > 0) {
  const catNames = { installations:'instalaciones', beaches:'playas', location:'ubicaci\u00f3n', reservation:'reserva', campingVideo:'video' };
  claudeMessages.push({ role: 'user', content: '[Ya se enviaron fotos/videos de: ' + sentCats.map(k => catNames[k]||k).join(', ') + ']' });
}

return [{ json: {
  phoneNumber, remoteJid, pushName, textMessage, redisKey,
  clientName, reservationInfoSent, followUpSent, mediaSentCategories,
  conversationHistory, claudeMessages,
  bookingState, lookupState,
  isImage, messageId,
  isFirstMessage: conversationHistory.length === 1
} }];

// ============================================================
// PROCESAR RESPUESTA Y ACCIONES — v6 FIXED v2
// ============================================================
const inputData = $input.first().json;
const context = $('Construir contexto conversacional').first().json;
const messageText = context.textMessage.toLowerCase();
const remoteJid = context.remoteJid;
const phoneNumber = context.phoneNumber;
let bookingState = context.bookingState || { phase: 'idle', data: {} };

// === DETECT IF INPUT COMES FROM RECEIPT PATH OR CLAUDE PATH ===
const isReceiptPath = !!inputData.receiptResult;
let rawText = '';
if (!isReceiptPath) {
  rawText = inputData.content?.[0]?.text || '';
}

// === PARSE STRUCTURED RESPONSE (only for Claude path) ===
let responseText = '';
let actionType = 'none';
let actionData = {};
let bookingStateUpdate = {};

if (!isReceiptPath && rawText) {
  const rm = rawText.match(/---RESPONSE---\s*([\s\S]*?)\s*---ACTION---/);
  const am = rawText.match(/---ACTION---\s*([\s\S]*?)\s*---ACTION_DATA---/);
  const adm = rawText.match(/---ACTION_DATA---\s*([\s\S]*?)\s*---BOOKING_STATE_UPDATE---/);
  const sum = rawText.match(/---BOOKING_STATE_UPDATE---\s*([\s\S]*?)\s*---END---/);

  if (rm) {
    responseText = rm[1].trim();
  } else {
    // Fallback: Claude didn't use the format — strip ALL markers and metadata
    responseText = rawText
      .replace(/---RESPONSE---/g, '')
      .replace(/---ACTION---[\s\S]*?---END---/g, '')
      .replace(/---ACTION---/g, '')
      .replace(/---ACTION_DATA---/g, '')
      .replace(/---BOOKING_STATE_UPDATE---/g, '')
      .replace(/---END---/g, '')
      .trim();
  }

  // Aggressive cleanup: strip ALL format artifacts
  responseText = responseText
    .split('\n')
    .filter(line => {
      const trimmed = line.trim();
      if (trimmed === '') return true;
      if (trimmed === 'none') return false;
      if (trimmed === '{}') return false;
      if (trimmed === '---') return false;
      if (trimmed === 'RESPONSE') return false;
      if (trimmed === 'ACTION') return false;
      if (trimmed === 'ACTION_DATA') return false;
      if (trimmed === 'BOOKING_STATE_UPDATE') return false;
      if (trimmed === 'END') return false;
      if (trimmed.startsWith('---RESPONSE')) return false;
      if (trimmed.startsWith('---ACTION')) return false;
      if (trimmed.startsWith('---BOOKING')) return false;
      if (trimmed.startsWith('---END')) return false;
      if (/^\{.*"phase".*\}$/.test(trimmed)) return false;
      if (/^\{.*"check(In|Out)".*\}$/.test(trimmed)) return false;
      if (trimmed === 'check_availability' || trimmed === 'create_booking' || trimmed === 'lookup_booking' || trimmed === 'cancel_booking') return false;
      return true;
    })
    .join('\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  if (am) actionType = am[1].trim().toLowerCase();
  if (adm) { try { const j = adm[1].trim(); if (j && j !== '{}') actionData = JSON.parse(j); } catch(e) {} }
  if (sum) { try { const j = sum[1].trim(); if (j && j !== '{}') bookingStateUpdate = JSON.parse(j); } catch(e) {} }
}

// Apply state update from Claude
if (bookingStateUpdate.phase) bookingState.phase = bookingStateUpdate.phase;
if (bookingStateUpdate.data) bookingState.data = { ...bookingState.data, ...bookingStateUpdate.data };
if (bookingStateUpdate.referenceCode) bookingState.referenceCode = bookingStateUpdate.referenceCode;

// === RECEIPT RESULT (from image verification path) ===
if (isReceiptPath) {
  const rr = inputData.receiptResult;
  bookingState = inputData.bookingState || bookingState;

  if (rr.datosCorrectos) {
    actionType = 'create_booking';
    actionData = {
      checkIn: bookingState.data.checkIn,
      checkOut: bookingState.data.checkOut,
      adults: bookingState.data.adults,
      children: bookingState.data.children,
      infants: bookingState.data.infants,
      guestName: bookingState.data.guestName,
      guestEmail: bookingState.data.guestEmail,
      guestPhone: bookingState.data.guestPhone || phoneNumber,
      guestCountry: bookingState.data.guestCountry || 'Costa Rica',
      depositCRC: rr.montoDetectado
    };
    responseText = '¡Tu comprobante fue verificado correctamente! Estoy creando tu reserva...';
  } else if (rr.maxAttemptsReached) {
    responseText = 'No pudimos verificar tu comprobante después de 3 intentos. Por favor contactá directamente a Don Jorge al *8303-4342* para completar tu reserva.';
  } else {
    const minMonto = Math.round(bookingState.data.totalCRC / 2);
    responseText = 'El comprobante no pudo ser verificado.';
    if (rr.razonFallo) responseText += ' Detalle: ' + rr.razonFallo + '.';
    responseText += '\n\nPor favor verificá que:\n1. El SINPE sea al *8303-4342* (Jorge Gerardo Jiménez Granados)\n2. El monto sea al menos *₡' + minMonto.toLocaleString() + '*\n\nEnviá de nuevo la foto del comprobante. Te quedan ' + (3 - rr.receiptAttempts) + ' intentos.';
  }
}

// === SAFETY: ensure responseText is never empty ===
if (!responseText || !responseText.trim()) {
  responseText = '¿En qué más te puedo ayudar?';
}

// === MULTIMEDIA (existing logic) ===
let mediaToSend = [];
const mediaSentCategories = context.mediaSentCategories || {};
const isFirstMessage = context.isFirstMessage;
const explicitMedia = ['foto','fotos','photo','photos','imagen','imagenes','imágenes','video','videos','mostrame','mostrarme','muéstrame','muestrame','mostrar','mandame','mándame','mandar','pasame','pásame','enseñame','enséñame','enseñar','quiero ver','quisiera ver','podés mostrar','podes mostrar','cómo se ve','como se ve','cómo es','como es','cómo luce','como luce'].some(t => messageText.includes(t));

if (isFirstMessage) {
  mediaToSend.push({ type: 'video', url: 'https://drive.google.com/uc?export=download&id=1FrfuFfpJ76NzWDOHxUoSSMwAujlRV-qM', caption: 'Acá es donde te vas a quedar 🌴' });
}

const installTriggers = ['instalacion','instalación','baño','ducha','servicio','cocina','rancho','comedor','parrilla','instalaciones'];
const beachTriggers = ['playa','playas','beach','conchal','minas','piratas','puerto viejo'];
const locTriggers = ['llegar','dirección','ubicación','donde queda','location','cómo llego','mapa'];

if (explicitMedia && installTriggers.some(t => messageText.includes(t))) {
  mediaToSend.push({ type: 'image', url: 'https://drive.google.com/uc?export=download&id=1StQ4Jjk4y3nKSdfVfZLQ_KgpVmcgPySB', caption: '*Área de Cocina*' });
  mediaToSend.push({ type: 'image', url: 'https://drive.google.com/uc?export=download&id=1a7rVzJ27psPYmJb2YEIoDdaZh9XC4-mU', caption: '*Duchas*' });
  mediaToSend.push({ type: 'video', url: 'https://drive.google.com/uc?export=download&id=1oCbDXLD781_ZEux6t4kiNg6aQ_QFz2MH', caption: '*Rancho*' });
  mediaSentCategories.installations = true;
}
if (explicitMedia && beachTriggers.some(t => messageText.includes(t))) {
  mediaToSend.push({ type: 'image', url: 'https://drive.google.com/uc?export=download&id=1FWoV9LOQEzmzWqgrnq9OazmH0ea9Dafj', caption: '*Playa Puerto Viejo*' });
  mediaToSend.push({ type: 'image', url: 'https://drive.google.com/uc?export=download&id=174PbyQhqU4NdW0ZTw1c-NNnxdSPmxjYQ', caption: '*Playa Conchal*' });
  mediaToSend.push({ type: 'image', url: 'https://drive.google.com/uc?export=download&id=1fYkA8y8Hw6TXP8Ekh3Dr0hLZCKATt_Sd', caption: '*Playa Minas*' });
  mediaToSend.push({ type: 'image', url: 'https://drive.google.com/uc?export=download&id=1wbbh2J8S1vsQu6ZRr8bzpMO9jLfPlGMF', caption: '*Bahía Piratas*' });
  mediaSentCategories.beaches = true;
}
if (explicitMedia && locTriggers.some(t => messageText.includes(t))) {
  mediaToSend.push({ type: 'image', url: 'https://drive.google.com/uc?export=download&id=1W9zKiiHar0QNQLypevHJ4_8d23ybBZzu', caption: '*Entrada del Camping*' });
  mediaSentCategories.location = true;
}

// === UPDATE HISTORY ===
const updatedHistory = context.conversationHistory;
updatedHistory.push({ role: 'assistant', content: responseText, timestamp: new Date().toISOString() });

let clientName = context.clientName;
if (!clientName) {
  const nm = responseText.match(/Gracias\s+(\w+)\s+por/i);
  if (nm) clientName = nm[1];
}

const redisData = JSON.stringify({
  messages: updatedHistory.slice(-20),
  clientName,
  reservationInfoSent: context.reservationInfoSent,
  followUpSent: context.followUpSent,
  mediaSentCategories,
  bookingState,
  lookupState: context.lookupState,
  lastInteraction: new Date().toISOString()
});

return [{ json: {
  phoneNumber, remoteJid, responseText,
  mediaToSend, hasMedia: mediaToSend.length > 0,
  redisKey: context.redisKey, redisData,
  actionType, actionData,
  hasAction: actionType !== 'none' && actionType !== '',
  bookingState
} }];

const data = $('Procesar respuesta y acciones').first().json;
const items = [];

for (const media of data.mediaToSend) {
  items.push({
    json: {
      remoteJid: data.remoteJid,
      phoneNumber: data.phoneNumber,
      mediaType: media.type,
      mediaUrl: media.url,
      caption: media.caption || ''
    }
  });
}

return items;

