const claudeResponse = $input.first().json;
const context = $('Construir contexto conversacional').first().json;
const bookingState = context.bookingState;
const montoEsperado = bookingState.data.totalCRC / 2;

const textContent = claudeResponse.content?.[0]?.text || '';
let extractedData = { monto: null, nombreDestinatario: null, celularDestino: null };
try {
  const jsonMatch = textContent.match(/\{[\s\S]*?\}/);
  if (jsonMatch) extractedData = JSON.parse(jsonMatch[0]);
} catch (e) { console.error('Parse error:', e.message); }

const montoDetectado = parseFloat(extractedData.monto) || 0;
const nombreDetectado = (extractedData.nombreDestinatario || '').toLowerCase().trim();
const celularDetectado = String(extractedData.celularDestino || '').replace(/[^0-9]/g, '');

const montoValido = montoDetectado >= (montoEsperado - 100) && montoDetectado <= (bookingState.data.totalCRC + 100);
const nombreValido = nombreDetectado.includes('jorge') && nombreDetectado.includes('jimenez');
const celularValido = celularDetectado === '83034342';
const datosCorrectos = montoValido && nombreValido && celularValido;
const receiptAttempts = (bookingState.receiptAttempts || 0) + 1;

const razonFallo = [];
if (!montoValido) razonFallo.push('monto: \u20a1' + montoDetectado.toLocaleString() + ' (esperado min \u20a1' + montoEsperado.toLocaleString() + ')');
if (!nombreValido) razonFallo.push('nombre: "' + extractedData.nombreDestinatario + '"');
if (!celularValido) razonFallo.push('celular: "' + extractedData.celularDestino + '"');

return [{
  json: {
    ...context,
    receiptResult: {
      datosCorrectos, montoDetectado, montoEsperado, montoValido, nombreValido, celularValido,
      receiptAttempts, maxAttemptsReached: receiptAttempts >= 3,
      razonFallo: razonFallo.join('; ')
    },
    bookingState: {
      ...bookingState,
      receiptAttempts,
      receiptVerified: datosCorrectos,
      depositCRC: datosCorrectos ? montoDetectado : 0,
      phase: datosCorrectos ? 'creating_booking' : (receiptAttempts >= 3 ? 'receipt_failed' : 'awaiting_payment')
    }
  }
}];

const data = $input.first().json;
const actionType = data.actionType;
const actionData = data.actionData;

const SUPABASE_URL = 'https://yvmzzgphvfvaovlmmjsa.supabase.co';
const SUPABASE_ANON_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inl2bXp6Z3BodmZ2YW92bG1tanNhIiwicm9sZSI6ImFub24iLCJpYXQiOjE3Njg0NzgyNDEsImV4cCI6MjA4NDA1NDI0MX0.PrHpkAE07XXiNLNoNQTxBxcmNSIjAj1t5fu13ibdjY4';
const headers = { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + SUPABASE_ANON_KEY, 'apikey': SUPABASE_ANON_KEY };

const http = this.helpers.httpRequest;

let result = { success: false, error: null, data: null };
try {
  if (actionType === 'check_availability') {
    const settings = await http({ method: 'GET', url: SUPABASE_URL + '/rest/v1/camping_settings?key=eq.max_capacity_persons&select=value', headers });
    const maxCap = parseInt(settings?.[0]?.value || '25', 10);
    const overlapping = await http({ method: 'GET', url: SUPABASE_URL + '/rest/v1/bookings?status=neq.cancelled&check_in=lt.' + actionData.checkOut + '&check_out=gt.' + actionData.checkIn + '&select=adults,children', headers });
    const occ = (overlapping || []).reduce((s, b) => s + (b.adults||0) + (b.children||0), 0);
    const req = actionData.guests || 0;
    result = { success: true, data: { available: (occ + req) <= maxCap, currentOccupancy: occ, maxCapacity: maxCap, spotsLeft: maxCap - occ } };

  } else if (actionType === 'create_booking') {
    const nights = Math.round((new Date(actionData.checkOut) - new Date(actionData.checkIn)) / 86400000);
    const totalGuests = (actionData.adults||0) + (actionData.children||0);
    const totalCRC = totalGuests * 7000 * nights;
    const depositCRC = actionData.depositCRC || Math.round(totalCRC / 2);
    const CRC_RATE = 500;
    const totalUSD = totalCRC / CRC_RATE;
    const nameParts = (actionData.guestName || 'WhatsApp').split(' ');

    const payload = {
      booking: {
        checkIn: actionData.checkIn, checkOut: actionData.checkOut,
        guests: { adults: actionData.adults||1, children: actionData.children||0, infants: actionData.infants||0 },
        accommodation: { bringOwnTent: true, rentedTents: [] }, addOns: [],
        guestInfo: {
          firstName: nameParts[0]||'', lastName: nameParts.slice(1).join(' ')||'',
          email: actionData.guestEmail||'', phone: actionData.guestPhone||'',
          country: actionData.guestCountry||'Costa Rica',
          specialRequests: 'Reserva creada via WhatsApp (Cori)'
        }
      },
      pricing: { campsiteFee: totalUSD, tentRental: 0, addOns: 0, subtotal: totalUSD, taxes: 0, total: totalUSD },
      depositCRC
    };

    const createResult = await http({ method: 'POST', url: SUPABASE_URL + '/functions/v1/create-booking', headers, body: payload, json: true });
    if (createResult.referenceCode) {
      result = { success: true, data: { referenceCode: createResult.referenceCode, totalCRC, depositCRC, balanceCRC: Math.max(0, totalCRC - depositCRC), nights } };
    } else {
      result = { success: false, error: createResult.error || 'Error creando reserva' };
    }

  } else if (actionType === 'lookup_booking') {
    const lookupResult = await http({ method: 'POST', url: SUPABASE_URL + '/functions/v1/lookup-booking', headers, body: { referenceCode: actionData.referenceCode }, json: true });
    result = { success: true, data: lookupResult };

  } else if (actionType === 'cancel_booking') {
    const ld = await http({ method: 'POST', url: SUPABASE_URL + '/functions/v1/lookup-booking', headers, body: { referenceCode: actionData.referenceCode }, json: true });
    if (!ld.found) { result = { success: false, error: 'Reserva no encontrada' }; }
    else {
      await http({ method: 'POST', url: SUPABASE_URL + '/functions/v1/cancel-booking', headers, body: { bookingId: ld.booking.id }, json: true });
      result = { success: true, data: { cancelled: true, referenceCode: actionData.referenceCode } };
    }
  }
} catch (e) { result = { success: false, error: e.message }; }

// Build follow-up text
let followUp = '';
if (result.success) {
  if (actionType === 'check_availability') {
    followUp = result.data.available
      ? '\n\n\u2705 \u00a1Hay disponibilidad! Quedan ' + result.data.spotsLeft + ' espacios.'
      : '\n\n\u274c No hay disponibilidad. Capacidad: ' + result.data.maxCapacity + ', ocupados: ' + result.data.currentOccupancy + '.';
  } else if (actionType === 'create_booking') {
    followUp = '\n\n\ud83c\udf89 *\u00a1Reserva creada!*\n\n\ud83d\udccb C\u00f3digo: *' + result.data.referenceCode + '*\n\ud83d\udcb0 Total: \u20a1' + result.data.totalCRC.toLocaleString() + '\n\ud83d\udcb3 Dep\u00f3sito: \u20a1' + result.data.depositCRC.toLocaleString() + '\n\ud83d\udcb5 Saldo: \u20a1' + result.data.balanceCRC.toLocaleString() + '\n\nGuard\u00e1 tu c\u00f3digo *' + result.data.referenceCode + '* \ud83c\udf34';
  } else if (actionType === 'lookup_booking' && result.data.found) {
    const b = result.data.booking;
    followUp = '\n\n\ud83d\udccb *Reserva ' + b.reference_code + '*\n\ud83d\udcc5 ' + b.check_in + ' \u2192 ' + b.check_out + '\n\ud83d\udc65 ' + b.adults + ' adultos, ' + b.children + ' ni\u00f1os\n\ud83d\udcb0 \u20a1' + (b.total||0).toLocaleString() + '\n\ud83d\udccc ' + (b.status==='confirmed'?'Confirmada \u2705':'Pendiente');
  } else if (actionType === 'cancel_booking') {
    followUp = '\n\n\u2705 Reserva *' + result.data.referenceCode + '* cancelada.';
  }
} else {
  followUp = '\n\n\u26a0\ufe0f ' + (result.error || 'Error desconocido') + '. Contact\u00e1 a Don Jorge: *8303-4342*.';
}

return [{ json: { ...data, responseText: data.responseText + followUp, actionResult: result,
  bookingState: { ...data.bookingState, lastActionResult: result,
    referenceCode: result.data?.referenceCode || data.bookingState?.referenceCode,
    phase: (actionType === 'create_booking' && result.success) ? 'done' : data.bookingState?.phase },
  // Update redisData with action result
  redisData: (() => {
    try {
      const rd = JSON.parse(data.redisData);
      rd.bookingState = { ...rd.bookingState, lastActionResult: result,
        referenceCode: result.data?.referenceCode || rd.bookingState?.referenceCode,
        phase: (actionType === 'create_booking' && result.success) ? 'done' : rd.bookingState?.phase };
      // Append follow-up to last assistant message
      const msgs = rd.messages || [];
      if (msgs.length > 0 && msgs[msgs.length-1].role === 'assistant') {
        msgs[msgs.length-1].content += followUp;
      }
      return JSON.stringify(rd);
    } catch(e) { return data.redisData; }
  })()
} }];
